import { createContext } from 'reka-ui'
import type { MeterRootContext } from './types'

export const [injectMeterRootContext, provideMeterRootContext] =
  createContext<MeterRootContext>('MeterRootContext')

export const useMeterRootContext = () => {
  const requiredKeys: (keyof MeterRootContext)[] = [
    'variant',
    'size',
    'value',
    'max',
    'min',
    'label',
    'percentage',
    'orientation',
    'meterId',
  ]

  const ctx = injectMeterRootContext()
  if (!ctx) {
    throw new Error('[Meter] useMeterRootContext must be used within a MeterRoot')
  }

  const missingKeys = requiredKeys.filter(key => !ctx[key])
  if (missingKeys.length > 0) {
    throw new Error(`[Meter] Missing required context property: "${missingKeys.join(', ')}".`)
  }

  return ctx
}

import { cva } from 'class-variance-authority'

export const meterVariants = cva('relative flex gap-2', {
  variants: {
    orientation: {
      horizontal: 'flex-col w-full',
      vertical: 'flex-col items-center min-h-[200px] h-full',
    },
  },
  defaultVariants: {
    orientation: 'horizontal',
  },
})

export const meterTrackVariants = cva(
  'relative overflow-hidden bg-secondary will-change-transform transition-all duration-300 ease-in-out',
  {
    variants: {
      orientation: {
        horizontal: 'w-full',
        vertical: 'flex-1 w-full flex flex-col-reverse',
      },
      size: {
        sm: '',
        default: '',
        lg: '',
      },
    },
    compoundVariants: [
      { orientation: 'horizontal', size: 'sm', class: 'h-1.5' },
      { orientation: 'horizontal', size: 'default', class: 'h-2' },
      { orientation: 'horizontal', size: 'lg', class: 'h-3' },
      { orientation: 'vertical', size: 'sm', class: 'w-1.5' },
      { orientation: 'vertical', size: 'default', class: 'w-2' },
      { orientation: 'vertical', size: 'lg', class: 'w-3' },
    ],
    defaultVariants: {
      size: 'default',
      orientation: 'horizontal',
    },
  },
)
export const meterIndicatorVariants = cva(
  'absolute will-change-[color] transition-all duration-300 ease-in-out',
  {
    variants: {
      orientation: {
        horizontal: 'h-full',
        vertical: 'w-full bottom-0',
      },
      variant: {
        default: 'bg-primary',
        success: 'bg-green-500',
        warning: 'bg-yellow-500',
        danger: 'bg-red-500',
      },
    },
    defaultVariants: {
      variant: 'default',
      orientation: 'horizontal',
    },
  },
)

export const meterHeaderVariants = cva('flex w-full', {
  variants: {
    orientation: {
      horizontal: 'items-center justify-between',
      vertical: 'flex-col items-center gap-1',
    },
  },
  defaultVariants: {
    orientation: 'horizontal',
  },
})

export { default as Meter } from './Meter.vue'
export { default as MeterHeader } from './MeterHeader.vue'
export { default as MeterIndicator } from './MeterIndicator.vue'
export { default as MeterLabel } from './MeterLabel.vue'
export { default as MeterTrack } from './MeterTrack.vue'
export { default as MeterValue } from './MeterValue.vue'

export type { MeterProps, MeterRootContext } from './types'
export { useMeterRootContext } from './context'
